using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

var topic = args.Length > 0
    ? string.Join(" ", args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Build the AI chat pipeline with automatic function invocation ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var notebook = new Notebook();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(SearchWeb,
            name: "search_web",
            description: "Search the web for information on a given query and return result snippets."),
        AIFunctionFactory.Create(notebook.SaveNote,
            name: "save_note",
            description: "Save a research note for later use when writing the summary."),
        AIFunctionFactory.Create(notebook.GetAllNotes,
            name: "get_notes",
            description: "Retrieve all previously saved research notes."),
    ]
};

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a meticulous research agent. When given a topic you must:
        1. Use the search_web tool at least 3 times with varied queries to explore
           different facets of the topic.
        2. After each search, save the most important findings with save_note.
        3. Once you have gathered enough material, call get_notes to review
           everything, then write a comprehensive summary that includes:
           - An overview of the topic
           - Key facts and recent developments
           - Different perspectives or debates (if any)
           - A brief conclusion
        Be thorough but concise. Cite sources where possible.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary:\n\n{topic}")
};

// --- Run the agent (function invocation middleware handles the tool-call loop) ---
Console.WriteLine("Agent is working…\n");

ChatResponse response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine(response.Text);

Console.WriteLine($"\n--- Research Complete ---");
Console.WriteLine($"📝 {notebook.Notes.Count} note(s) collected during research.");

// ---------------------------------------------------------------------------
// Helper: prompt for a topic interactively
// ---------------------------------------------------------------------------
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine();
    return string.IsNullOrWhiteSpace(input) ? "recent advances in artificial intelligence" : input;
}

// ---------------------------------------------------------------------------
// Tool: Web Search via DuckDuckGo HTML endpoint (no API key required)
// ---------------------------------------------------------------------------
[Description("Search the web for information on the given query")]
static async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await http.GetStringAsync(url);
        var parsed = ParseSearchResults(html);
        return parsed.Length > 0
            ? parsed
            : "No results found. Try rephrasing the query.";
    }
    catch (Exception ex)
    {
        return $"Search failed ({ex.Message}). Try a different query.";
    }
}

// ---------------------------------------------------------------------------
// Parsing helpers
// ---------------------------------------------------------------------------
static string ParseSearchResults(string html)
{
    var titles = Regex.Matches(html, @"<a\s+class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline);
    var snippets = Regex.Matches(html, @"<a\s+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline);
    var urls = Regex.Matches(html, @"<a\s+class=""result__url""[^>]*href=""([^""]*?)""", RegexOptions.Singleline);

    var count = Math.Min(5, Math.Min(titles.Count, snippets.Count));
    if (count == 0)
        return string.Empty;

    var sb = new StringBuilder();
    for (var i = 0; i < count; i++)
    {
        var title = StripHtml(titles[i].Groups[1].Value);
        var snippet = StripHtml(snippets[i].Groups[1].Value);
        var link = i < urls.Count ? WebUtility.HtmlDecode(urls[i].Groups[1].Value).Trim() : "";

        sb.AppendLine($"[{i + 1}] {title}");
        if (!string.IsNullOrWhiteSpace(link))
            sb.AppendLine($"    URL: {link}");
        sb.AppendLine($"    {snippet}");
        sb.AppendLine();
    }

    return sb.ToString();
}

static string StripHtml(string value)
    => Regex.Replace(WebUtility.HtmlDecode(value), "<[^>]+>", "").Trim();

// ---------------------------------------------------------------------------
// Tool: Notebook for collecting research notes
// ---------------------------------------------------------------------------
sealed class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Save a research note for later use in the final summary")]
    public string SaveNote([Description("The note text to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({Notes.Count} total)");
        return $"Note saved. You now have {Notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes")]
    public string GetAllNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < Notes.Count; i++)
            sb.AppendLine($"[Note {i + 1}] {Notes[i]}");
        return sb.ToString();
    }
}

